CREATE TABLE packages (
  id INT AUTO_INCREMENT PRIMARY KEY,
  title VARCHAR(255) NOT NULL,
  duration VARCHAR(100) NOT NULL,
  price DECIMAL(10,2) NOT NULL,
  type VARCHAR(50), 
  description TEXT,
  image VARCHAR(255)
);

INSERT INTO `packages` (`id`, `title`, `duration`, `price`, `type`, `description`, `image`) VALUES
(1, 'Dehradun & Uttarakhand', '6 Nights / 5 Days', 25000.00, 'Family/Group/Couple', 'Uttarakhand, also known as the “Land of Gods”, is famous for its scenic beauty, holy rivers, peaceful hill stations, and breathtaking Himalayan views. This tour offers a perfect blend of nature, spirituality, and adventure. Explore the calm valleys of Dehradun, the picturesque hills of Mussoorie, the serene banks and yoga culture of Rishikesh, and the divine aura of Haridwar’s Ganga Aarti. Whether you are traveling with family, friends, partner traveler, this tour ensures relaxation, natural beauty, culture, and unforgettable memories.', '1762608840_8644_1762574479_4155_dhr2.jpg,1762608840_9903_1762574479_7531_dhr3.jpg,1762608855_6296_dhr4.jpg,1762664799_6278_1762574479_8194_dhr1.jpg'),
(2, 'Goa', '5 Nights / 6 Days', 23000.00, 'Family/Group/Couple', 'Goa is one of India’s most popular beach destinations, known for its golden sandy shores, blue waters, thrilling water sports, historic churches, and vibrant nightlife. This 5 Nights / 6 Days Goa Tour Package offers a perfect combination of relaxation, sightseeing, and leisure time. Enjoy the lively beaches of North Goa such as Calangute, Baga, and Vagator, explore the serene beauty of South Goa, visit the famous Basilica of Bom Jesus and Se Cathedral, and soak in the scenic views from Dona Paula. The package also includes exciting activities like water sports and an enjoyable evening River Cruise on the Mandovi River. Comfortable hotel stays, transportation, and a memorable holiday experience are included to make your trip unforgettabl', '1762607311_4591_goa2.jpg,1762666541_6908_goa.jpeg,1762666541_5678_goa3.jpg,1762666541_2589_goa4.jpg'),
(3, 'Ooty – Maysor', '8 Nights / 9 Days', 21000.00, 'Family/Group/Couple', 'Ooty, also known as Udhagamandalam, is a serene hill station located in the Nilgiri Mountains. Famous for its cool climate, lush green valleys, majestic tea gardens, and mist-covered hills, Ooty offers a refreshing escape from the busy city life. Major attractions include Botanical Garden, Ooty Lake, Doddabetta Peak, Rose Garden, and the iconic Nilgiri Mountain Toy Train, which provides a scenic journey through forests and tea plantations. It is a perfect destination for nature lovers, couples, and families. \r\n>>   Mysore, known as the Cultural Capital of Karnataka, is renowned for its royal heritage, grand architecture, and vibrant tradition. The magnificent Mysore Palace, Chamundi Hills, St. Philomena’s Church, and Mysore Zoo are among the top attractions. The city is also famous for silk sarees, sandalwood products, and rich history. Mysore beautifully blends culture, art, and historic elegance, making it a must-visit destination.', '1762667848_2141_ottyas.jpg,1762667914_1223_1762665046_2226_ottytea.jpg,1762667914_9445_1762665046_4629_otty.jpg,1762667914_8193_1762665046_7872_otty3.jpg,1762667914_1267_1762666327_1929_maysor1.jpg,1762667914_1500_1762666862_1025_otty5.jpg');





CREATE TABLE `bookings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `package_id` int(11) NOT NULL,
  `package_name` varchar(255) DEFAULT NULL,
  `hotel_id` int(11) DEFAULT NULL,
  `hotel_name` varchar(255) DEFAULT NULL,
  `hotel_star` varchar(20) DEFAULT NULL,
  `image` text DEFAULT NULL,
  `adults` int(11) NOT NULL,
  `children` int(11) NOT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `hotel` varchar(255) NOT NULL,
  `checkin` date NOT NULL,
  `checkout` date NOT NULL,
  `status` varchar(20) DEFAULT 'Confirm',
  `booked_on` timestamp NOT NULL DEFAULT current_timestamp(),
  `booking_date` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


INSERT INTO `bookings` (`id`, `user_id`, `package_id`, `package_name`, `hotel_id`, `hotel_name`, `hotel_star`, `image`, `adults`, `children`, `price`, `hotel`, `checkin`, `checkout`, `status`, `booked_on`, `booking_date`) VALUES
(1, 2, 2, 'Goa', 15, 'Hotel Rajpurohit', '4 Star', '1762867146_5s5.jpg', 2, 0, 4400.00, '', '2025-11-17', '2025-11-25', 'Pending', '2025-11-12 05:26:48', '2025-11-12 05:26:48');



CREATE TABLE `itineraries` (
  `id` int(11) NOT NULL,
  `package_id` int(11) NOT NULL,
  `day_or_night` varchar(50) NOT NULL,
  `plan` text NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `itineraries` (`id`, `package_id`, `day_or_night`, `plan`) VALUES
(1, 2, '5/6', 'Day 1: Arrival in Goa\n • Arrive at Goa Airport or Railway Station\n • Transfer to hotel and check-in\n • Welcome drink on arrival (Non-Alcoholic)\n • Free time to relax or visit nearby beach\n • Overnight stay at hotel\n\nDay 2: North Goa Sightseeing\n • Breakfast at hotel\n • Visit Calangute Beach\n • Visit Baga Beach\n • Visit Candolim Beach\n • Visit Vagator Beach\n • Visit Fort Aguada\n • Water sports available at extra cost\n • Return to hotel and overnight stay\n\nDay 3: South Goa Sightseeing\n • Breakfast at hotel\n • Visit Basilica of Bom Jesus\n • Visit Se Cathedral\n • Visit St. Augustine Tower\n • Visit Mangeshi Temple or Shantadurga Temple\n • Visit Dona Paula Viewpoint\n • Visit Miramar Beach\n • Return to hotel and overnight stay\n\nDay 4: Leisure Day\n • Breakfast at hotel\n • Day free for personal activities\n • Optional activities at extra cost: Water sports, Island Trip, Shopping\n • Overnight stay at hotel\n\nDay 5: Mandovi River Cruise\n • Breakfast at hotel\n • Free time to relax at the beach or resort\n • Evening Mandovi River Cruise with music and cultural dance\n • Return to hotel and overnight stay\n\nDay 6: Departure\n • Breakfast at hotel\n • Check-out at hotel '),
(2, 1, '5/6', ' Day 1 – Arrival in Dehradun : \r\n • Arrival at Dehradun Airport / Railway Station\r\n • Meet & Greet, then transfer to the hotel\r\n • After check-in, visit Forest Research Institute, Tapkeshwar Temple\r\n • Evening free for shopping at Paltan Bazaar\r\n • Overnight stay in Dehradun\r\n\r\nDay 2 – Dehradun → Mussoorie :\r\n\r\n • After breakfast, drive to Mussoorie — the “Queen of Hills”\r\n • Visit Kempty Falls, Company Garden, Gun Hill Point, Camel’s Back Road\r\n • Evening stroll along Mall Road for shopping & street food\r\n • Overnight stay at Mussoorie\r\n\r\n🗓 Day 3 – Mussoorie Sightseeing :\r\n • Morning breakfast at the hotel\r\n • Excursion to Lal Tibba (the highest point) and Mussoorie Lake\r\n • Optional: Ropeway ride or paragliding experience (seasonal)\r\n • Dinner & overnight stay at Mussoorie\r\n\r\n🗓 Day 4 – Mussoorie → Rishikesh (85 km / 3 hrs)\r\n • Drive down to Rishikesh\r\n • Visit Lakshman Jhula, Ram Jhula, Triveni Ghat, Parmarth Niketan Ashram\r\n • Witness the evening Ganga Aarti at Triveni Ghat — a spiritual highlight\r\n • Overnight stay in Rishikesh\r\n\r\nDay 5 – Rishikesh → Haridwar  → Dehradun : \r\n • Morning transfer to Haridwar for sightseeing: Har Ki Pauri, Mansa Devi  • Temple, Daksha Mahadev Temple\r\n • Explore local markets for handicrafts & Ayurvedic products\r\n • Later return to Dehradun\r\n • Overnight stay in Dehradun\r\n\r\nDay 6 – Departure :\r\nBreakfast at hotel, check-out, and transfer to Airport / Railway Station\r\nTour ends with pleasant memories of the Himalayas \r\n'),
(3, 3, 'asdasd', 'Day 1 – Arrival in Bangalore\r\nArrive at Bangalore Airport / Railway Station\r\nMeet & greet by representative, then transfer to hotel\r\nVisit Lalbagh Botanical Garden, Cubbon Park, Vidhana Soudha, Bangalore Palace\r\nEvening at MG Road for shopping & local dining\r\nOvernight stay in Bangalore\r\n\r\n🗓 Day 2 – Bangalore → Mysore (145 km / 3 hrs)\r\nAfter breakfast, drive to Mysore (City of Palaces)\r\nEn route visit Srirangapatna (Tipu Sultan’s Fort, Dariya Daulat Palace)\r\nCheck-in at hotel\r\nEvening visit to the Mysore Palace, beautifully lit at night\r\nOvernight stay in Mysore\r\n\r\n🗓 Day 3 – Mysore Sightseeing\r\nBreakfast at hotel\r\nVisit Chamundi Hills, Nandi Bull Temple, Mysore Zoo, Brindavan Gardens (musical fountain show at night)\r\nExplore local silk saree & sandalwood shops\r\nOvernight stay in Mysore\r\n\r\n🗓 Day 4 – Mysore → Ooty (125 km / 4 hrs)\r\nMorning drive through scenic forested hills to Ooty – the “Queen of Hills”\r\nEn route visit Bandipur National Park or Mudumalai Wildlife Sanctuary\r\nCheck-in at hotel in Ooty\r\nEvening at leisure around Ooty Lake or Botanical Gardens\r\n\r\nOvernight stay in Ooty\r\n\r\n🗓 Day 5 – Ooty Sightseeing\r\n\r\nBreakfast at hotel\r\n\r\nVisit Doddabetta Peak, Tea Factory & Museum, Rose Garden, Government Botanical Garden\r\n\r\nEnjoy boating at Ooty Lake\r\n\r\nEvening walk around Charing Cross or Commercial Street\r\nOvernight stay in Ooty\r\n\r\n🗓 Day 6 – Ooty → Coonoor Excursion\r\nMorning toy train (optional) ride from Ooty to Coonoor\r\nVisit Sim’s Park, Lamb’s Rock, Dolphin’s Nose Viewpoint, and Highfield Tea Estate\r\nReturn to Ooty for overnight stay\r\n\r\n🗓 Day 7 – Ooty → Wayanad (140 km / 4 hrs)\r\nAfter breakfast, depart for Wayanad, Kerala\r\nEn route enjoy forest landscapes and waterfalls\r\nVisit Pookode Lake, Lakkidi View Point, Chain Tree, Banasura Sagar Dam\r\nCheck-in at hotel and relax\r\nOvernight stay in Wayanad\r\n\r\n🗓 Day 8 – Wayanad Sightseeing\r\nVisit Edakkal Caves, Soochipara Waterfalls, and Wayanad Wildlife Sanctuary\r\n\r\nExperience Kerala’s cultural blend and local cuisine\r\n\r\nOvernight stay in Wayanad\r\n\r\n🗓 Day 9 – Wayanad → Bangalore (280 km / 6 hrs) – Departure : \r\nBreakfast at hotel, check-out, and drive back to Bangalore\r\nDrop-off at Airport / Railway Station\r\nTour ends with sweet memories of South India');



